"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[59645],{64419(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>l,frontMatter:()=>a,metadata:()=>i,toc:()=>d});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 23 Borrowing Costs/over-time-transfer-of-constructed-go-aa70bd8985","title":"Over Time Transfer of Constructed Good (IAS 23)","description":"March 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 23 Borrowing Costs/Over Time Transfer of Constructed Good (IAS 23).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 23 Borrowing Costs","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-23-borrowing-costs-c7e76e1ff5/over-time-transfer-of-constructed-go-aa70bd8985","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-23-borrowing-costs-c7e76e1ff5/over-time-transfer-of-constructed-go-aa70bd8985","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"over-time-transfer-of-constructed-go-aa70bd8985","title":"Over Time Transfer of Constructed Good (IAS 23)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-23-borrowing-costs-c7e76e1ff5/over-time-transfer-of-constructed-go-aa70bd8985","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Translation of a Hyperinflationary Foreign Operation\u2014Presenting Exchange Differences (IAS 21 and IAS 29)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-21-and-ias-29-41dd7e0b1f/translation-of-a-hyperinflationary-f-21b5a63e3b"},"next":{"title":"Investment in a subsidiary accounted for at cost: Step acquisition (IAS 27)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-27-separate-financial-statements-ad3bcbac8c/investment-in-a-subsidiary-accounted-58c9158598"}}');var s=n(74848),o=n(28453);let a={id:"over-time-transfer-of-constructed-go-aa70bd8985",title:"Over Time Transfer of Constructed Good (IAS 23)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-23-borrowing-costs-c7e76e1ff5/over-time-transfer-of-constructed-go-aa70bd8985",sidebar_position:1},r="Over Time Transfer of Constructed Good (IAS 23)",c={},d=[];function f(e){let t={blockquote:"blockquote",h1:"h1",header:"header",p:"p",strong:"strong",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"over-time-transfer-of-constructed-good-ias-23",children:"Over Time Transfer of Constructed Good (IAS 23)"})}),"\n",(0,s.jsx)(t.p,{children:"March 2019"}),"\n",(0,s.jsx)(t.p,{children:"The Committee received a request about the capitalisation of borrowing costs in relation to the construction of a residential multi-unit real estate development (building)."}),"\n",(0,s.jsx)(t.p,{children:"In the fact pattern described in the request:"}),"\n",(0,s.jsx)(t.p,{children:"a. a real estate developer (entity) constructs the building and sells the individual units in the building to customers.\nb. the entity borrows funds specifically for the purpose of constructing the building and incurs borrowing costs in connection with that borrowing.\nc. before construction begins, the entity signs contracts with customers for the sale of some of the units in the building (sold units).\nd. the entity intends to enter into contracts with customers for the remaining part-constructed units (unsold units) as soon as it finds suitable customers.\ne. the terms of, and relevant facts and circumstances relating to, the entity\u2019s contracts with customers (for both the sold and unsold units) are such that, applying paragraph 35(c) of IFRS 15 Revenue from Contracts with Customers, the entity transfers control of each unit over time and, therefore, recognises revenue over time. The consideration promised by the customer in the contract is in the form of cash or another financial asset."}),"\n",(0,s.jsx)(t.p,{children:"The request asked whether the entity has a qualifying asset as defined in IAS 23 and, therefore, capitalises any directly attributable borrowing costs."}),"\n",(0,s.jsx)(t.p,{children:"Applying paragraph 8 of IAS 23, an entity capitalises borrowing costs that are directly attributable to the acquisition, construction or production of a qualifying asset as part of the cost of that asset. Paragraph 5 of IAS 23 defines a qualifying asset as \u2018an asset that necessarily takes a substantial period of time to get ready for its intended use or sale\u2019."}),"\n",(0,s.jsx)(t.p,{children:"Accordingly, the entity assesses whether, in the fact pattern described in the request, it recognises an asset that necessarily takes a substantial period of time to get ready for its intended use or sale. Depending on the particular facts and circumstances, the entity might recognise a receivable, a contract asset and/or inventory."}),"\n",(0,s.jsx)(t.p,{children:"The Committee concluded that, in the fact pattern described in the request:"}),"\n",(0,s.jsx)(t.p,{children:"a. a receivable that the entity recognises is not a qualifying asset. Paragraph 7 of IAS 23 specifies that financial assets are not qualifying assets.\nb. a contract asset that the entity recognises is not a qualifying asset. The contract asset (as defined in Appendix A to IFRS 15) would represent the entity\u2019s right to consideration that is conditioned on something other than the passage of time in exchange for transferring control of a unit. The intended use of the contract asset \u2014to collect cash or another financial asset\u2014is not a use for which it necessarily takes a substantial period of time to get ready.\nc. inventory (work-in-progress) for unsold units under construction that the entity recognises is not a qualifying asset. In the fact pattern described in the request, this asset is ready for its intended sale in its current condition\u2014ie the entity intends to sell the part-constructed units as soon as it finds suitable customers and, on signing a contract with a customer, will transfer control of any work-in- progress relating to that unit to the customer."}),"\n",(0,s.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IAS 23 provide an adequate basis for an entity to determine whether to capitalise borrowing costs in the fact pattern described in the request. Consequently, the Committee decided not to add this matter to its standard-setting agenda."}),"\n",(0,s.jsxs)(t.blockquote,{children:["\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Educational Material"}),"\nEducational material relating to the Committee's conclusion in this agenda decision is\navailable on the IAS 23 supporting materials page."]}),"\n"]})]})}function l(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(f,{...e})}):f(e)}},28453(e,t,n){n.d(t,{R:()=>a,x:()=>r});var i=n(96540);let s={},o=i.createContext(s);function a(e){let t=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),i.createElement(o.Provider,{value:t},e.children)}}}]);